SELECT

FROM ai_form_design_apply_log a

    a.del_flag = #{DEL_FLAG_NORMAL}

        AND a.draft_id = #{draftId}


        AND a.version_id = #{versionId}


        AND a.gen_table_id = #{genTableId}


        AND a.apply_type = #{applyType}


ORDER BY a.create_date DESC

SELECT

FROM ai_form_design_apply_log a

    a.del_flag = #{entity.DEL_FLAG_NORMAL}

        AND a.draft_id = #{entity.draftId}


        AND a.version_id = #{entity.versionId}


        AND a.gen_table_id = #{entity.genTableId}


        AND a.apply_type = #{entity.applyType}


ORDER BY a.create_date DESC

mapper.update:
UPDATE ai_form_design_apply_log SET
    del_flag = #{DEL_FLAG_DELETE}
WHERE id = #{id}
